CREATE TYPE "Role" AS ENUM ('STUDENT', 'ADMIN');
CREATE TYPE "ContentStatus" AS ENUM ('DRAFT', 'PUBLISHED', 'ARCHIVED');
CREATE TABLE "User" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "email" TEXT NOT NULL UNIQUE, "passwordHash" TEXT NOT NULL, "role" "Role" NOT NULL DEFAULT 'STUDENT', "avatarUrl" TEXT, "phone" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "StudentProfile" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL UNIQUE REFERENCES "User"("id") ON DELETE CASCADE, "registration" TEXT NOT NULL UNIQUE, "course" TEXT NOT NULL, "className" TEXT NOT NULL);
CREATE TABLE "Event" ("id" TEXT PRIMARY KEY, "title" TEXT NOT NULL, "slug" TEXT NOT NULL UNIQUE, "description" TEXT NOT NULL, "imageUrl" TEXT, "startsAt" TIMESTAMP(3) NOT NULL, "endsAt" TIMESTAMP(3), "location" TEXT NOT NULL, "category" TEXT NOT NULL, "capacity" INTEGER, "status" "ContentStatus" NOT NULL DEFAULT 'DRAFT', "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "EventRegistration" ("id" TEXT PRIMARY KEY, "eventId" TEXT NOT NULL REFERENCES "Event"("id") ON DELETE CASCADE, "userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("eventId", "userId"));
CREATE TABLE "Club" ("id" TEXT PRIMARY KEY, "name" TEXT NOT NULL, "slug" TEXT NOT NULL UNIQUE, "description" TEXT NOT NULL, "imageUrl" TEXT, "leader" TEXT NOT NULL, "meetingInfo" TEXT NOT NULL, "category" TEXT NOT NULL, "memberLimit" INTEGER, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "ClubMembership" ("id" TEXT PRIMARY KEY, "clubId" TEXT NOT NULL REFERENCES "Club"("id") ON DELETE CASCADE, "userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE, "joinedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, UNIQUE("clubId", "userId"));
CREATE TABLE "CalendarEntry" ("id" TEXT PRIMARY KEY, "title" TEXT NOT NULL, "description" TEXT, "startsAt" TIMESTAMP(3) NOT NULL, "endsAt" TIMESTAMP(3), "type" TEXT NOT NULL, "location" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "News" ("id" TEXT PRIMARY KEY, "title" TEXT NOT NULL, "slug" TEXT NOT NULL UNIQUE, "summary" TEXT NOT NULL, "content" TEXT NOT NULL, "imageUrl" TEXT, "category" TEXT NOT NULL, "status" "ContentStatus" NOT NULL DEFAULT 'DRAFT', "pinned" BOOLEAN NOT NULL DEFAULT false, "publishedAt" TIMESTAMP(3), "authorId" TEXT NOT NULL REFERENCES "User"("id"), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "Menu" ("id" TEXT PRIMARY KEY, "weekStart" TIMESTAMP(3) NOT NULL UNIQUE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "MenuItem" ("id" TEXT PRIMARY KEY, "menuId" TEXT NOT NULL REFERENCES "Menu"("id") ON DELETE CASCADE, "date" TIMESTAMP(3) NOT NULL, "mealType" TEXT NOT NULL, "name" TEXT NOT NULL, "ingredients" TEXT, "allergens" TEXT, "tags" TEXT[]);
CREATE TABLE "ClassSchedule" ("id" TEXT PRIMARY KEY, "className" TEXT NOT NULL, "weekday" INTEGER NOT NULL, "startsAt" TEXT NOT NULL, "endsAt" TEXT NOT NULL, "subject" TEXT NOT NULL, "teacher" TEXT NOT NULL, "room" TEXT NOT NULL);
CREATE TABLE "Notification" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE, "title" TEXT NOT NULL, "message" TEXT NOT NULL, "link" TEXT, "readAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "User_role_idx" ON "User"("role");
CREATE INDEX "Event_startsAt_status_idx" ON "Event"("startsAt", "status");
CREATE INDEX "CalendarEntry_startsAt_type_idx" ON "CalendarEntry"("startsAt", "type");
CREATE INDEX "News_status_publishedAt_idx" ON "News"("status", "publishedAt");
CREATE INDEX "Notification_userId_readAt_idx" ON "Notification"("userId", "readAt");
